$_MODULE['<{prestablog}prestashop>ai_3fb66787028092600f08cd2c37cc1027'] = 'Jeg administrerer en hjemmeside, der fokuserer på emnet %theme%. Kan du foreslå nogle blogemner, jeg bør udvikle? Formater svaret som en HTML-tabel med to kolonner: en til \'Emne\' og en til \'Popularitetsscore\' (et tal mellem 1 og 100). Hvert emne skal være i en separat række.';
$_MODULE['<{prestablog}prestashop>ai_3c299be1cf8d8948c25b1433eecc542f'] = 'Brug emnet "%theme%". Opret en tabel med titel- og søgeordsvariationer, der grupperer long-tail-termer, der kan rangere i søgemaskiner. Formater svaret som en HTML-tabel med to kolonner: en til titlerne og en til søgeordene.';
$_MODULE['<{prestablog}prestashop>ai_1065948d549c2bc51ea828181f2328cf'] = 'Jeg vil have dig til at skrive en SEO-optimeret blogartikel om emnet "%theme%", med en skrivestil af "%style%". Struktur teksten i HTML med passende tags. Artiklen skal være engagerende, relevant, af høj kvalitet og ikke kunne opdages som AI-genereret indhold. Start med et introduktionsafsnit uden at nævne bloggen eller bruge en overskrift. Brug underoverskrifter formateret med h2- og h3-tags, der inkorporerer long-tail-titler for at forbedre SEO. Integrer naturligt long-tail-søgeord og fremhæv dem med strong-tags. Sørg for, at hvert afsnit indeholder mindst 100 ord, med glidende overgange. Afslut med et resume, der understøtter de vigtigste punkter uden at tilføje nye oplysninger.';
$_MODULE['<{prestablog}prestashop>ai_bdfb00881e5b80ef206858f72db30420'] = 'Opret en fængslende introduktion, der vil blive vist i blogkategorien for at præsentere artiklen "%theme%". Denne introduktion skal være kortfattet, engagerende og give en generel oversigt over artiklens indhold.';
$_MODULE['<{prestablog}prestashop>ai_dceabd505243b76be8191a63ff37046c'] = 'Baseret på emnet "%theme%", opret en overbevisende titel, der fanger opmærksomheden og effektivt opsummerer indholdet. Og inkluder ikke anførselstegn omkring dit svar';
$_MODULE['<{prestablog}prestashop>ai_23e8bc5c05172b396e2a5bad9b1d6e7f'] = 'Baseret på emnet "%theme%", opret en kort og effektiv meta-titel, der er SEO-venlig og nøjagtigt repræsenterer indholdet. Og inkluder ikke anførselstegn omkring dit svar';
$_MODULE['<{prestablog}prestashop>ai_cb71ee03fd4e763b82325c5fa0c28711'] = 'Baseret på emnet "%theme%", opret en kortfattet og overbevisende meta-beskrivelse, der opfordrer til klik og er optimeret til søgemaskiner. Og inkluder ikke anførselstegn omkring dit svar';
